        int num = 0;
        char op = '+';
        int res = 0;
        for (int i = 0; i < s.size(); i++) {
            if (isdigit(s[i])) {
                num = num * 10 + (s[i] - '0');
            }
            if (s[i] == '+' || s[i] == '-' || s[i] == '*' || s[i] == '/' || i == s.size() - 1) {
                if (op == '+') {
                    res += num;
                } else if (op == '-') {
                    res -= num;
